1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office - quote (premium)", () => {
5	  // Fee-only baseline
6	  it("should charge 5 G (fee only) for an empty item list", () => {
7	    expect(quote([], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(5);
8	  });
9	
10	  // Single main item base premiums + fee
11	  it("should quote a single sword at 115 G (100 base + 10 first + 5 fee)", () => {
12	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(115);
13	  });
14	  it("should quote a single amulet at 71 G (60 base + 6 first + 5 fee)", () => {
15	    expect(quote([{ type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(71);
16	  });
17	  it("should quote a single staff at 93 G (80 base + 8 first + 5 fee)", () => {
18	    expect(quote([{ type: "staff" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(93);
19	  });
20	  it("should quote a single potion at 49 G (40 base + 4 first + 5 fee)", () => {
21	    expect(quote([{ type: "potion" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(49);
22	  });
23	
24	  // Multiple main items sum their base premiums
25	  it("should sum base premiums for a sword and an amulet to 181 G (160 base + 16 first + 5 fee)", () => {
26	    expect(quote([{ type: "sword" }, { type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(181);
27	  });
28	
29	  // Component base premiums
30	  it("should quote a single rune at 33 G (25 base + 2.5 first + 5 fee, rounded up)", () => {
31	    expect(quote([{ type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(33);
32	  });
33	  it("should quote 2 runes at 60 G (50 base + 5 first + 5 fee)", () => {
34	    expect(quote([{ type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(60);
35	  });
36	
37	  // Building block of 3 alike components
38	  it("should quote 3 runes as a block at 71 G (60 base + 6 first + 5 fee)", () => {
39	    expect(quote([{ type: "rune" }, { type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(71);
40	  });
41	  it("should quote 4 runes at 115 G (no block, 100 base + 10 first + 5 fee)", () => {
42	    expect(
43	      quote([{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })
44	    ).toBe(115);
45	  });
46	  it("should quote 7 runes at 198 G (175 base + 17.5 first + 5 fee, rounded up)", () => {
47	    expect(
48	      quote(
49	        [
50	          { type: "rune" },
51	          { type: "rune" },
52	          { type: "rune" },
53	          { type: "rune" },
54	          { type: "rune" },
55	          { type: "rune" },
56	          { type: "rune" },
57	        ],
58	        { yearsWithMHPCO: 0, isFollowUp: false }
59	      )
60	    ).toBe(198);
61	  });
62	
63	  // Alike = same type only
64	  it("should not form a block for 2 runes + 1 moonstone (75 base + 7.5 first + 5 fee = 88 G, rounded up)", () => {
65	    expect(
66	      quote([{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], { yearsWithMHPCO: 0, isFollowUp: false })
67	    ).toBe(88);
68	  });
69	  it("should form two separate blocks for 3 runes + 3 moonstones (120 base + 12 first + 5 fee = 137 G)", () => {
70	    expect(
71	      quote(
72	        [
73	          { type: "rune" },
74	          { type: "rune" },
75	          { type: "rune" },
76	          { type: "moonstone" },
77	          { type: "moonstone" },
78	          { type: "moonstone" },
79	        ],
80	        { yearsWithMHPCO: 0, isFollowUp: false }
81	      )
82	    ).toBe(137);
83	  });
84	
85	  // Item-specific modifiers
86	  it("should add 50% curse surcharge to the cursed item's base premium", () => {
87	    expect(quote([{ type: "sword", cursed: true }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(170);
88	  });
89	  it("should add 30% high-enchantment surcharge for enchantment >= 5", () => {
90	    expect(quote([{ type: "sword", enchantment: 5 }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(148);
91	  });
92	  it("should not add high-enchantment surcharge for enchantment 4", () => {
93	    expect(quote([{ type: "sword", enchantment: 4 }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(115);
94	  });
95	  it("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item", () => {
96	    expect(quote([{ type: "sword", cursed: true, enchantment: 5 }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(203);
97	  });
98	
99	  // Modifier scope on multi-item policies
100	  it("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before policy modifiers)", () => {
101	    expect(quote([{ type: "sword", cursed: true }, { type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(236);
102	  });
103	
104	  // Policy-wide modifiers
105	  it("should apply 20% loyalty discount for a customer with exactly 2 years", () => {
106	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 2, isFollowUp: false })).toBe(95);
107	  });
108	  it("should apply 10% first-insurance surcharge to the policy base premium", () => {
109	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(115);
110	  });
111	  it("should apply 15% follow-up discount on quotes after the customer's first quote", () => {
112	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 0, isFollowUp: true })).toBe(100);
113	  });
114	
115	  // Rounding up in MHPCO's favor
116	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
117	
118	  // Integration examples
119	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
120	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
121	
122	  // Error case
123	  it.todo("should reject a quote containing an item with an unknown type");
124	});
125	
126	describe("Claim Office - claim (payout)", () => {
127	  // Standard reimbursement minus deductible
128	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
129	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
130	
131	  // High-enchantment clause
132	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
133	
134	  // Dragon-material clause
135	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
136	
137	  // Conflict: 50% rule wins over dragon
138	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
139	
140	  // Threshold confirmation
141	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
142	
143	  // Deductible per damage event
144	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
145	
146	  // Cap behaviour
147	  it.todo("should cap total payout at twice the insurance sum");
148	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
149	
150	  // Rounding down in MHPCO's favor
151	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
152	
153	  // Error cases
154	  it.todo("should reject a claim whose damage entry references an item not in the policy");
155	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
156	  it.todo("should reject a claim with a negative damage amount");
157	});
