1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PRICE = 60;
19	
20	const COMPONENT_TYPES = ["rune", "moonstone"];
21	
22	const LOYALTY_YEARS_THRESHOLD = 2;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	
25	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
26	
27	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	
33	const isComponent = (item: { type: string }): boolean =>
34	  COMPONENT_TYPES.includes(item.type);
35	
36	const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM[item.type];
37	
38	const itemPremium = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
39	  const base = basePremiumFor(item);
40	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
41	  const isHighEnchantment = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
42	  const highEnchantmentSurcharge = isHighEnchantment ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
43	  return base + curseSurcharge + highEnchantmentSurcharge;
44	};
45	
46	const componentGroupPremium = (type: string, count: number): number =>
47	  count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];
48	
49	const loyaltyDiscountFor = (policyBasePremium: number, context: QuoteContext): number =>
50	  context.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT_RATE : 0;
51	
52	const firstInsuranceSurchargeFor = (policyBasePremium: number): number =>
53	  policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
54	
55	const followUpDiscountFor = (policyBasePremium: number, context: QuoteContext): number =>
56	  context.isFollowUp ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
57	
58	export function quote(items: { type: string; cursed?: boolean; enchantment?: number }[], context: QuoteContext): number {
59	  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
60	    const count = items.filter((item) => item.type === type).length;
61	    return sum + componentGroupPremium(type, count);
62	  }, 0);
63	
64	  const mainItemsPremium = items
65	    .filter((item) => !isComponent(item))
66	    .reduce((sum, item) => sum + itemPremium(item), 0);
67	
68	  const policyBasePremium = mainItemsPremium + componentBasePremium;
69	
70	  const policyModifiers =
71	    -loyaltyDiscountFor(policyBasePremium, context) +
72	    firstInsuranceSurchargeFor(policyBasePremium) -
73	    followUpDiscountFor(policyBasePremium, context);
74	
75	  const premium = policyBasePremium + policyModifiers + POLICY_FEE;
76	
77	  return Math.ceil(premium);
78	}
79	
80	export function claim(): unknown {
81	  return undefined;
82	}
